import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); 
  const [modo, setModo] = useState(''); 
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const [processando, setProcessando] = useState(false);
  const [relatorio, setRelatorio] = useState([]);
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, [etapa, modo]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const valorLimpo = codigo.trim(); // MANTÉM LETRAS (Ex: F001)

      if (!valorLimpo || processando) { setCodigo(""); return; }
      setProcessando(true);

      try {
        if (etapa === 'login') {
          const res = await axios.post('http://localhost:3001/login', { codBarras: valorLimpo });
          setUsuario(res.data);
          setEtapa('escolha');
          setMensagem(`Olá, ${res.data.nome}!`);
        } else if (etapa === 'acao') {
          const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
          const res = await axios.post(`http://localhost:3001${url}`, { 
            usuarioId: usuario.id, 
            ferramentacod: valorLimpo 
          });
          setMensagem(`✅ ${res.data}`);
          setTimeout(() => setMensagem(modo === 'retirada' ? "Bipe o PRÓXIMO item" : "Bipe a PRÓXIMA devolução"), 2000);
        }
      } catch (err) {
        setMensagem(`❌ ${err.response?.data || "Erro na conexão"}`);
      } finally {
        setCodigo("");
        setTimeout(() => { setProcessando(false); inputRef.current?.focus(); }, 500);
      }
    }
  };

  const carregarRelatorio = async () => {
    const res = await axios.get('http://localhost:3001/admin/status-ferramentas');
    setRelatorio(res.data);
  };

  return (
    <div style={{ textAlign: 'center', fontFamily: 'Arial', padding: '20px' }}>
      <h1>TSEA Rastreabilidade</h1>
      <div style={{ background: 'white', padding: '20px', borderRadius: '10px', boxShadow: '0 0 10px #ccc', display: 'inline-block', minWidth: '400px' }}>
        <h2>{mensagem}</h2>
        
        {(etapa === 'login' || etapa === 'acao') && (
          <input 
            ref={inputRef}
            value={codigo} 
            onChange={(e) => setCodigo(e.target.value)} 
            onKeyDown={handleKeyPress} 
            placeholder="Aguardando bip..." 
            style={{ padding: '10px', fontSize: '18px', width: '80%' }}
            disabled={processando}
          />
        )}

        {etapa === 'escolha' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            <button onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("MODO RETIRADA"); }} style={{ padding: '15px', backgroundColor: '#0055ff', color: 'white', border: 'none', cursor: 'pointer' }}>RETIRAR FERRAMENTA</button>
            <button onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("MODO DEVOLUÇÃO"); }} style={{ padding: '15px', backgroundColor: '#28a745', color: 'white', border: 'none', cursor: 'pointer' }}>DEVOLVER FERRAMENTA</button>
            {usuario.tipo === 'admin' && <button onClick={() => { setEtapa('admin'); carregarRelatorio(); }} style={{ padding: '15px', backgroundColor: '#666', color: 'white', border: 'none' }}>PAINEL ADMIN</button>}
            <button onClick={() => window.location.reload()} style={{ background: 'none', color: 'red', border: 'none', cursor: 'pointer' }}>Sair</button>
          </div>
        )}

        {etapa === 'admin' && (
          <div>
            <table border="1" style={{ width: '100%', marginTop: '20px', borderCollapse: 'collapse' }}>
              <thead><tr><th>Item</th><th>Status</th><th>Com quem?</th></tr></thead>
              <tbody>
                {relatorio.map((r, i) => (
                  <tr key={i}>
                    <td>{r.nome}</td>
                    <td style={{ color: r.status === 'disponivel' ? 'green' : 'red' }}>{r.status}</td>
                    <td>{r.usuario_atual || '--'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
            <button onClick={() => setEtapa('escolha')} style={{ marginTop: '10px' }}>Voltar</button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
